const path = require('path');

// Define the root directory where files are allowed to be accessed from.
const ROOT_DIR = '/safe/files/directory';

function validateFilename(filename) {
    // Normalize the filename to ensure it doesn't contain any invalid characters or paths.
    const normalizedPath = path.normalize(path.join(ROOT_DIR, filename));

    // Check if the normalized path is still within the root directory.
    return path.isAbsolute(normalizedPath) && !path.relative(ROOT_DIR, normalizedPath).startsWith('..');
